require"UI.UIBase"require"UI.UIBlock"UI_RollNotice_New=UIBase:Inherit()UI_RollNotice_New.EType={Roll=1,Maintenance=2}UI_RollNotice_New.ENoticeType={Interval=1,ConfigTime=2}function UI_RollNotice_New:OnCreate()UI_RollNotice_New.Inst=self;self.notice_strid=tonumber(ExcelMgr.GetData("global","global",2).args)self.show_time=tonumber(ExcelMgr.GetData("global","global",3).args)local a=ExcelMgr.GetData("global","global",1).args;self.config_time=Tools.SplitToNumbers(a,',')self.timer_close=TimerMgr:Init()self.timer_fetch_roll=TimerMgr:Init()self.timer_fetch_maintain=TimerMgr:Init()self.timer_show_roll=TimerMgr:Init()self.timer_show_maintain=TimerMgr:Init()LobbyNetMgr.AddMsgListener('NotifyRollingNotice',function()self:FetchRollNotice()end)LobbyNetMgr.AddMsgListener('NotifyMaintainNotice',function()self:FetchMaintainNotice()end)end;function UI_RollNotice_New:FetchRollNotice()self.timer_fetch_roll:ClearAllTimers()self.timer_fetch_roll:Loop(5,-1,function()local b=Tools.GetRealTime()if LobbyNetMgr.isOK()and GameMgr.Inst.account_id~=-1 and b and b>0 then self.timer_fetch_roll:ClearAllTimers()local c=ProtoMgr.CreateRequest('Lobby','fetchRollingNotice')c.lang=GameMgr.Inst.prefer_language;LobbyNetMgr.SendRequest('Lobby','fetchRollingNotice',c,function(d,e)if d or e.error and e.error.code~=0 then else self:TryShowNotice(UI_RollNotice_New.EType.Roll,e.notice)end end)end end)end;function UI_RollNotice_New:FetchMaintainNotice()self.timer_fetch_maintain:ClearAllTimers()self.timer_fetch_maintain:Loop(5,-1,function()local b=Tools.GetRealTime()if LobbyNetMgr.isOK()and GameMgr.Inst.account_id~=-1 and b and b>0 then self.timer_fetch_maintain:ClearAllTimers()local c=ProtoMgr.CreateRequest('Lobby','fetchMaintainNotice')LobbyNetMgr.SendRequest('Lobby','fetchMaintainNotice',c,function(d,e)if d or e.error and e.error.code~=0 then else self:TryShowNotice(UI_RollNotice_New.EType.Maintenance,e.notice)end end)end end)end;function UI_RollNotice_New:TryShowNotice(f,g)local h=Tools.GetRealTime()if f==UI_RollNotice_New.EType.Roll then if g and g.content then self.roll_notice=g end;if not self.roll_notice then return end;self.timer_show_roll:ClearAllTimers()if h<self.roll_notice.end_time then local i=self.roll_notice.end_time-h;local j=0;if self.roll_notice.repeat_type==UI_RollNotice_New.ENoticeType.Interval then local k=self.roll_notice.end_time;local l=self.roll_notice.repeat_interval;while i>l and k-l>=self.roll_notice.start_time do i=i-l;k=k-l end;j=i elseif self.roll_notice.repeat_type==UI_RollNotice_New.ENoticeType.ConfigTime then table.sort(self.roll_notice.repeat_time)j=i-self.roll_notice.repeat_time[1]*60;for m=1,#self.roll_notice.repeat_time do local n=i-self.roll_notice.repeat_time[m]*60;if n>0 and n<j then j=n end end end;if j>0 then self.timer_show_roll:Delay(j,function()if UI_RollNotice and UI_RollNotice.Inst then UIMgr.Inst:ShowUI(UI_RollNotice.className,nil,{content=self.roll_notice.content})end;self.timer_show_roll:Delay(5,function()self:TryShowNotice(f,nil)end)end)end end elseif f==UI_RollNotice_New.EType.Maintenance then if g and g.maintain_time then self.maintain_time=g.maintain_time end;if not self.maintain_time then return end;self.timer_show_maintain:ClearAllTimers()local j=0;local o=0;local i=self.maintain_time-h;if i<=0 then return end;for m=1,#self.config_time do j=i-self.config_time[m]if j>0 then o=self.config_time[m]break end end;if j>0 then self.timer_show_maintain:Delay(j,function()self:ShowNotice(o)self.timer_show_maintain:Delay(5,function()self:TryShowNotice(f,nil)end)end)end end end;function UI_RollNotice_New:ShowNotice(o)local p=""if o<=0 then return else if o<=59 then p=Tools.StrOfLocalization(20177,o)else o=o/60;p=Tools.StrOfLocalization(20176,o)end end;self.text_notice.text=self:SetTextColor(Tools.StrOfLocalization(self.notice_strid,p))self:Show()end;function UI_RollNotice_New:SetTextColor(q)q=string.gsub(q,"%[tag%]","<color=#ff5b53>")q=string.gsub(q,"%[/tag%]","</color>")return q end;function UI_RollNotice_New:Show()self.locking=true;self.transform.gameObject:SetActive(true)self.timer_close:ClearAllTimers()self.timer_close:Delay(self.show_time,function()self:Close()end)self.transform:SetPos(0,115)self:DoRectMove(self.transform,Vector2(0,0),0.15,function()self.locking=false end)end;function UI_RollNotice_New:Close()if self.locking then return end;self.locking=true;self.timer_close:ClearAllTimers()self:DoRectMove(self.transform,Vector2(0,115),0.15,function()self.locking=false;self.transform.gameObject:SetActive(false)end)end;return UI_RollNotice_New